-- Addon namespace
local _, Private = ...
local L = Private.Libs.ACL

-- Global environment
local _G = _G

-- Toggle Cooldown Viewer helper function
function Private:ShowCooldownViewerSettings()
	if not _G.CooldownViewerSettings then return end

	if not _G.CooldownViewerSettings:IsShown() then
		_G.CooldownViewerSettings:Show()
	else
		_G.CooldownViewerSettings:Hide()
	end
end

-- AyijeCDM profile
function Private:Setup_ACDM(installer)
	if not Private.IsAddOnLoaded('Ayije_CDM') then Private:Print('AyijeCDM ' .. L["is not installed or enabled."]) return end

	-- Disable unused ElvUI elements
	if Private.ElvUI then
		ElvUI[1].db.unitframe.units.player.power.enable = false
	end

	-- Global dbs
	local dev, scaled = Private.Addon.db.global.dev, Private.Addon.db.global.scaled

	-- Profile name
	local name = (dev and 'Luckyone') or 'Luckyone ' .. Private.Version

	-- Profile string
	local importString = [[!ACDM:]]

	-- Profile import
	local API = _G.Ayije_CDM_API
	API:ImportProfile(importString, name)

	if scaled then -- 1080p x/y offsets
		_G.Ayije_CDMDB.profiles[name].editModePositions.BuffBarCooldownViewer.Default.x = -288
        _G.Ayije_CDMDB.profiles[name].editModePositions.BuffBarCooldownViewer.Default.y = -100
		_G.Ayije_CDMDB.profiles[name].editModePositions.BuffIconCooldownViewer.Default.y = -113
		_G.Ayije_CDMDB.profiles[name].editModePositions.EssentialCooldownViewer.Default.y = -146
	end

	if installer then
		_G.LuckyoneInstallStepComplete:ShowMessage(L["AyijeCDM profile has been set."])
	end

	Private:Print(L["AyijeCDM profile has been set."])
	Private:Print(L["Note: If the position is wrong after the UI reload, use X and Y offset in the /acdm Positions tab to adjust it."])
end

-- SkironCooldownManager profile
function Private:Setup_SCM(installer)
	if not Private.IsAddOnLoaded('SkironCooldownManager') then Private:Print('SkironCooldownManager ' .. L["is not installed or enabled."]) return end

	-- Disable unused ElvUI elements
	if Private.ElvUI then
		ElvUI[1].db.unitframe.units.player.castbar.enable = false
		ElvUI[1].db.unitframe.units.player.power.enable = false
		ElvUI[1].private.unitframe.disabledBlizzardFrames.castbar = false
	end

	-- Global dbs
	local dev, scaled = Private.Addon.db.global.dev, Private.Addon.db.global.scaled

	-- Profile name
	local name = (dev and 'Luckyone') or 'Luckyone ' .. Private.Version

	-- Profile string
	local importString = [[!SCM:1:0!]]

	-- Profile import
	local API = _G.SCMAPI
	API.ImportProfile(name, importString)

	if scaled then -- 1080p ANCHOR:1 Y offset
		local DB = _G.SkironCooldownManagerDB
		if DB then
			DB.profiles[name].options.anchorConfig[1].anchor = { 'CENTER', 'ElvUIParent,UIParent', 'CENTER', 0, -163 }
		end
	end

	if installer then
		_G.LuckyoneInstallStepComplete:ShowMessage(L["SkironCooldownManager profile has been set."])
	end

	Private:Print(L["SkironCooldownManager profile has been set."])
	Private:Print(L["Note: If the position is wrong after the UI reload, use X and Y offset in the /scm Cooldown Manager - Specialization: Icons tab to adjust it."])
end
